import os
import uuid
import imghdr
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'secure_uploads', 'profiles')
MAX_CONTENT_LENGTH = 2 * 1024 * 1024  # 2 MB max file size
ALLOWED_MIME_TYPES = {'image/jpeg', 'image/png', 'image/gif', 'image/webp'}
ALLOWED_EXTENSIONS = {'jpg', 'jpeg', 'png', 'gif', 'webp'}
# Mapping from imghdr detection results to file extensions
IMGHDR_TO_EXT = {
    'jpeg': 'jpg',
    'png': 'png',
    'gif': 'gif',
    'webp': 'webp',
}

app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

# Ensure upload directory exists with restrictive permissions
os.makedirs(UPLOAD_FOLDER, mode=0o750, exist_ok=True)


def validate_image_content(file_stream):
    """
    Validate image content by reading magic bytes using imghdr.
    Returns the detected image type or None if invalid.
    """
    header = file_stream.read(512)
    file_stream.seek(0)

    detected_type = imghdr.what(None, h=header)

    # Additional check for WEBP since imghdr may not detect it
    if detected_type is None:
        if header[:4] == b'RIFF' and header[8:12] == b'WEBP':
            detected_type = 'webp'

    return detected_type


def validate_image_dimensions(file_stream, max_width=4096, max_height=4096):
    """
    Validate image dimensions to prevent decompression bombs.
    Uses PIL with a pixel limit safeguard.
    """
    try:
        from PIL import Image

        # Set a reasonable pixel limit to prevent decompression bombs
        Image.MAX_IMAGE_PIXELS = max_width * max_height

        file_stream.seek(0)
        img = Image.open(file_stream)
        img.verify()  # Verify it's a valid image without fully loading
        file_stream.seek(0)

        # Re-open to check dimensions (verify() closes the image)
        img = Image.open(file_stream)
        width, height = img.size
        file_stream.seek(0)

        if width > max_width or height > max_height:
            return False, f"Image dimensions {width}x{height} exceed maximum {max_width}x{max_height}"

        if width < 1 or height < 1:
            return False, "Image has invalid dimensions"

        return True, None
    except ImportError:
        # If PIL is not available, skip dimension check but log a warning
        file_stream.seek(0)
        app.logger.warning("Pillow not installed; skipping image dimension validation")
        return True, None
    except Exception as e:
        file_stream.seek(0)
        return False, f"Image validation failed: {str(e)}"


def generate_safe_filename(detected_type):
    """
    Generate a server-side filename using UUID, ignoring the original filename entirely.
    """
    ext = IMGHDR_TO_EXT.get(detected_type, 'bin')
    return f"{uuid.uuid4().hex}.{ext}"


@app.route('/api/profile/upload', methods=['POST'])
def upload_profile_picture():
    """
    Upload a profile picture with comprehensive security validation.
    """
    # Check if file is present in request
    if 'profile_picture' not in request.files:
        return jsonify({'error': 'No file provided. Use field name "profile_picture".'}), 400

    file = request.files['profile_picture']

    if file.filename == '' or file.filename is None:
        return jsonify({'error': 'No file selected.'}), 400

    # Step 1: Check declared MIME type (untrusted, but useful as a first filter)
    if file.content_type not in ALLOWED_MIME_TYPES:
        return jsonify({
            'error': f'Invalid file type "{file.content_type}". Allowed types: {", ".join(ALLOWED_MIME_TYPES)}'
        }), 400

    # Step 2: Check original file extension (untrusted, secondary filter)
    original_filename = secure_filename(file.filename)
    if original_filename:
        ext = original_filename.rsplit('.', 1)[-1].lower() if '.' in original_filename else ''
        if ext not in ALLOWED_EXTENSIONS:
            return jsonify({
                'error': f'Invalid file extension ".{ext}". Allowed: {", ".join(ALLOWED_EXTENSIONS)}'
            }), 400

    # Step 3: Validate actual file content using magic bytes (TRUSTED validation)
    detected_type = validate_image_content(file.stream)
    if detected_type not in IMGHDR_TO_EXT:
        return jsonify({
            'error': 'File content does not match a valid image format. '
                     'The file may be corrupted or not a genuine image.'
        }), 400

    # Step 4: Check file size explicitly (belt-and-suspenders with MAX_CONTENT_LENGTH)
    file.stream.seek(0, os.SEEK_END)
    file_size = file.stream.tell()
    file.stream.seek(0)

    if file_size == 0:
        return jsonify({'error': 'Uploaded file is empty.'}), 400

    if file_size > MAX_CONTENT_LENGTH:
        return jsonify({
            'error': f'File size {file_size} bytes exceeds maximum of {MAX_CONTENT_LENGTH} bytes.'
        }), 400

    # Step 5: Validate image dimensions to prevent decompression bombs
    dimensions_valid, dimension_error = validate_image_dimensions(file.stream)
    if not dimensions_valid:
        return jsonify({'error': dimension_error}), 400

    # Step 6: Generate a safe server-side filename (never use client-provided name)
    safe_filename = generate_safe_filename(detected_type)
    file_path = os.path.join(UPLOAD_FOLDER, safe_filename)

    # Step 7: Ensure the resolved path is within the upload directory (path traversal protection)
    real_upload_folder = os.path.realpath(UPLOAD_FOLDER)
    real_file_path = os.path.realpath(file_path)
    if not real_file_path.startswith(real_upload_folder + os.sep):
        return jsonify({'error': 'Invalid file path detected.'}), 400

    # Step 8: Optionally re-encode the image to strip metadata and embedded payloads
    try:
        from PIL import Image
        file.stream.seek(0)
        img = Image.open(file.stream)

        # Convert to RGB if necessary (strips alpha for JPEG, normalizes format)
        if detected_type == 'jpeg' and img.mode != 'RGB':
            img = img.convert('RGB')

        # Save re-encoded image (strips EXIF, comments, and other metadata)
        save_format = {
            'jpeg': 'JPEG',
            'png': 'PNG',
            'gif': 'GIF',
            'webp': 'WEBP',
        }.get(detected_type, 'PNG')

        img.save(real_file_path, format=save_format, quality=90)
        app.logger.info(f"Re-encoded and saved profile picture: {safe_filename}")

    except ImportError:
        # If PIL is not available, save the raw validated file
        file.stream.seek(0)
        file.save(real_file_path)
        app.logger.warning(
            f"Pillow not installed; saved raw file without re-encoding: {safe_filename}"
        )
    except Exception as e:
        app.logger.error(f"Error processing image: {str(e)}")
        return jsonify({'error': 'Failed to process the uploaded image.'}), 500

    # Set restrictive file permissions
    os.chmod(real_file_path, 0o640)

    return jsonify({
        'message': 'Profile picture uploaded successfully.',
        'filename': safe_filename,
        'size': file_size,
        'detected_type': detected_type,
    }), 201


@app.errorhandler(413)
def request_entity_too_large(error):
    """Handle file size exceeding MAX_CONTENT_LENGTH."""
    return jsonify({
        'error': f'File too large. Maximum size is {MAX_CONTENT_LENGTH // (1024 * 1024)} MB.'
    }), 413


@app.errorhandler(400)
def bad_request(error):
    return jsonify({'error': 'Bad request.'}), 400


if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)